const keyOf = (value) => JSON.stringify(value)

function bump(m, value, delta) {
  const k = keyOf(value)
  const existing = m.get(k)
  m.set(k, [value, (existing ? existing[1] : 0) + delta])
}

function consolidate(m) {
  for (const [k, [, count]] of m) if (count === 0) m.delete(k)
  return m
}

export class Collection {
  constructor(inner) {
    this.inner = inner
  }

  static empty() {
    return new Collection(new Map())
  }

  static fromArray(items) {
    const m = new Map()
    for (const x of items) bump(m, x, 1)
    return new Collection(consolidate(m))
  }

  static fromEntries(entries) {
    const m = new Map()
    for (const [value, mult] of entries) bump(m, value, mult)
    return new Collection(consolidate(m))
  }

  entries() {
    return [...this.inner.values()].filter(([, count]) => count !== 0)
  }
  add(value, mult) {
    const m = new Map(this.inner)
    bump(m, value, mult)
    return new Collection(consolidate(m))
  }

  concat(other) {
    const m = new Map(this.inner)
    for (const [, [value, count]] of other.inner) bump(m, value, count)
    return new Collection(consolidate(m))
  }

  negate() {
    const m = new Map()
    for (const [k, [value, count]] of this.inner) m.set(k, [value, -count])
    return new Collection(m)
  }

  map(f) {
    const m = new Map()
    for (const [, [value, count]] of this.inner) bump(m, f(value), count)
    return new Collection(consolidate(m))
  }

  filter(pred) {
    const m = new Map()
    for (const [, [value, count]] of this.inner) if (pred(value)) bump(m, value, count)
    return new Collection(consolidate(m))
  }
}

